## Testing tools

Use `clear_registry()` between tests:

```rust
use protomcp::{tool, ToolResult, ArgDef, clear_registry};
use protomcp::tool::with_registry;

#[test]
fn test_add() {
    clear_registry();
    tool("add")
        .description("Add two numbers")
        .arg(ArgDef::int("a"))
        .arg(ArgDef::int("b"))
        .handler(|_, _| ToolResult::new("3"))
        .register();

    with_registry(|tools| {
        assert_eq!(tools.len(), 1);
        assert_eq!(tools[0].name, "add");
    });
    clear_registry();
}
```

